import React from 'react';
import { motion } from 'framer-motion';

const classData = [
  {
    title: "The Prodigy",
    suffix: "Junior Batches",
    image: "https://images.unsplash.com/photo-1502519144081-acca18599776?auto=format&fit=crop&w=600&q=80",
    desc: "Ages 4-12. Building foundations with joy and technique."
  },
  {
    title: "The Urban",
    suffix: "Teen Squad",
    image: "https://images.unsplash.com/photo-1535525153412-5a42439a210d?auto=format&fit=crop&w=600&q=80",
    desc: "Ages 13-19. Focus on style, performance, and expression."
  },
  {
    title: "Mastery",
    suffix: "Adult Open Class",
    image: "https://images.unsplash.com/photo-1518834107812-67b0b7c58434?auto=format&fit=crop&w=600&q=80",
    desc: "For those who never stopped dreaming. All levels."
  }
];

const ladiesBatch = {
  title: "Empowerment",
  suffix: "Ladies Only",
  image: "https://images.unsplash.com/photo-1495750186196-805179373977?auto=format&fit=crop&w=1200&q=80",
  desc: "A private, premium space for women to rediscover themselves through movement."
};

const Academy = () => {
  return (
    <div className="pt-32 pb-24 px-6">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-20">
          <motion.h1 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-5xl font-cinzel mb-4"
          >
            The Academy
          </motion.h1>
          <div className="h-px w-40 gold-gradient mx-auto mb-6" />
          <p className="text-gold tracking-widest uppercase text-sm">Curation of Excellence</p>
        </div>

        {/* Regular Batches */}
        <div className="grid md:grid-cols-3 gap-8 mb-24">
          {classData.map((item, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.2 }}
              viewport={{ once: true }}
              className="group relative h-[500px] overflow-hidden border border-gold/20"
            >
              <img src={item.image} alt={item.title} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 grayscale group-hover:grayscale-0" />
              <div className="absolute inset-0 bg-gradient-to-t from-charcoal via-charcoal/20 to-transparent" />
              <div className="absolute inset-0 p-8 flex flex-col justify-end">
                <h3 className="text-3xl font-cinzel text-white leading-tight">{item.title}</h3>
                <p className="text-gold font-montserrat uppercase tracking-widest text-xs mb-4">{item.suffix}</p>
                <div className="h-px w-0 group-hover:w-full transition-all duration-500 bg-gold mb-4" />
                <p className="text-ivory/0 group-hover:text-ivory/100 transition-opacity duration-500 text-sm font-light">
                  {item.desc}
                </p>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Ladies empowerment Section */}
        <motion.div
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
          className="relative h-[400px] overflow-hidden rounded-sm border-2 border-gold/30"
        >
          <img src={ladiesBatch.image} alt="Ladies" className="w-full h-full object-cover opacity-50" />
          <div className="absolute inset-0 bg-charcoal/40 flex items-center justify-center text-center p-6">
            <div className="max-w-2xl">
              <h2 className="text-4xl font-cinzel text-gold-gradient mb-2">{ladiesBatch.title}</h2>
              <p className="tracking-[0.3em] font-montserrat uppercase text-sm mb-6">Premium Ladies Batch</p>
              <p className="text-ivory/80 italic mb-8 uppercase tracking-widest text-xs">{ladiesBatch.desc}</p>
              <button className="bg-gold text-charcoal px-8 py-3 font-bold uppercase tracking-widest text-xs hover:bg-white transition-colors border border-gold">
                Inquire for Privates
              </button>
            </div>
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default Academy;
